// ─────────────────────────────────────────────────────────────
// FILTER & ENRICH ECOMMERCE REVIEW DATA
// Handles Tokopedia, Shopee, Lazada, Bukalapak, Amazon
// ─────────────────────────────────────────────────────────────
const item = $input.item.json;

// --- 1. Resolve nested data from MrScraper response ---
let rootData =
  item?.data?.data?.data ||
  item?.data?.data ||
  item?.data ||
  {};

// --- 2. Extract review fields (map common field names across platforms) ---
const reviewText =
  rootData.review_text ||
  rootData.review ||
  rootData.content ||
  rootData.ulasan ||
  rootData.text ||
  rootData.body ||
  '';

const rating =
  parseFloat(rootData.rating ||
  rootData.star ||
  rootData.stars ||
  rootData.score || 0);

const reviewerName =
  rootData.reviewer ||
  rootData.reviewer_name ||
  rootData.user ||
  rootData.username ||
  'Anonymous';

const reviewDate =
  rootData.review_date ||
  rootData.date ||
  rootData.created_at ||
  rootData.published_at ||
  new Date().toISOString();

const photoCount =
  parseInt(rootData.photo_count ||
  rootData.images_count ||
  rootData.photos || 0);

const helpfulVotes =
  parseInt(rootData.helpful ||
  rootData.helpful_votes ||
  rootData.likes || 0);

const isVerified =
  rootData.verified_purchase ||
  rootData.verified ||
  false;

const sellerReply =
  rootData.seller_reply ||
  rootData.shop_reply ||
  rootData.response ||
  '';

// --- 3. Word count filter ---
const wordCount =
  reviewText.split(/\s+/).filter(w => w.length > 0).length || 0;

// Skip reviews under 10 words UNLESS rating is very low (1-2 stars = still valuable signal)
if (wordCount < 10 && rating > 2) {
  return [{
    json: {
      skip: true,
      reason: 'Review too short and not a critical rating',
      rating,
      wordCount
    }
  }];
}

// --- 4. Deduplication hash (reviewer + date + first 50 chars) ---
const hashBase = `${reviewerName}|${reviewDate}|${reviewText.slice(0, 50)}`;
const reviewHash = hashBase.split('').reduce((acc, char) => {
  return ((acc << 5) - acc + char.charCodeAt(0)) | 0;
}, 0).toString(36);

// --- 5. Pre-flag viral risk (before AI — fast check) ---
const viralRiskPreflag =
  photoCount >= 3 ||
  helpfulVotes >= 10 ||
  rating === 1 ||
  reviewText.length > 500;

// --- 6. Infer sentiment from rating alone for text-less reviews ---
let ratingOnlySentiment = null;
if (wordCount < 10) {
  if (rating <= 2) ratingOnlySentiment = 'negative';
  else if (rating === 3) ratingOnlySentiment = 'neutral';
  else ratingOnlySentiment = 'positive';
}

// --- 7. Return enriched review ---
return [{
  json: {
    skip: false,
    // Review core data
    reviewText: reviewText.slice(0, 4000), // Trim to max 4000 chars for AI
    rating,
    reviewerName,
    reviewDate,
    photoCount,
    helpfulVotes,
    isVerified,
    sellerReply,
    wordCount,
    reviewHash,
    viralRiskPreflag,
    ratingOnlySentiment,
    // Product context (passed from Google Sheets)
    productName: $('Get Target Product List').item.json.Product_Name || rootData.product_name || '',
    skuCode: $('Get Target Product List').item.json.SKU_Code || '',
    platform: $('Get Target Product List').item.json.Platform || rootData.platform || '',
    category: $('Get Target Product List').item.json.Category || '',
    productUrl: $('Get Target Product List').item.json.Product_URL || '',
    brandName: $('Get Target Product List').item.json.Brand_Name || 'YourBrand',
    // Workflow config
    slackChannel: '// Input your Slack channel name e.g. #brand-monitoring',
    slackAlertChannel: '// Input your Slack alert channel name e.g. #brand-alerts',
    notionDatabaseId: '// Input your Notion Database ID',
    competitorKeywords: 'competitor1, competitor2, competitor3',
    alertThreshold: 2.5,
    runDate: new Date().toISOString()
  }
}];

