=Analyze the following ecommerce product review for the brand "{{ $json.brandName }}".

Product: {{ $json.productName }}
SKU: {{ $json.skuCode }}
Platform: {{ $json.platform }}
Category: {{ $json.category }}
Star Rating: {{ $json.rating }} / 5
Reviewer: {{ $json.reviewerName }}
Review Date: {{ $json.reviewDate }}
Verified Purchase: {{ $json.isVerified }}
Photo Count: {{ $json.photoCount }}
Helpful Votes: {{ $json.helpfulVotes }}
Seller Reply Exists: {{ $json.sellerReply ? 'Yes' : 'No' }}

Review Text:
{{ $json.reviewText }}

Known Competitors to detect: {{ $json.competitorKeywords }}

Return ONLY this exact JSON structure, no markdown, no explanation:

{
  "sentiment_label": "positive | neutral | negative",
  "sentiment_score": number between -1.0 and 1.0,
  "emotion_tags": ["array of emotions: frustration | delight | anger | loyalty | confusion | disappointment | trust | excitement | skepticism"],
  "product_dimension": "quality | delivery | packaging | pricing | authenticity | customer_service | after_sales | overall",
  "key_phrase": "most impactful sentence from the review (max 20 words)",
  "summary": "2 sentence summary of the review in English",
  "competitor_mentions": ["array of competitor brand names mentioned, or empty array []"],
  "urgency_level": "low | medium | high | critical",
  "response_suggestion": "suggested CS reply to this review (max 40 words)",
  "viral_risk": true or false,
  "viral_reason": "why this review could go viral, or empty string",
  "brand_loyalty_signal": true or false,
  "awareness_source": "first_time | repeat | referral_mention | unknown",
  "action_required": true or false,
  "action_reason": "why action is needed, or empty string",
  "cx_score": number between 1 and 10
}

