// ─────────────────────────────────────────────────────────────
// PARSE AI RESPONSE & FORMAT ALL OUTPUT FIELDS
// ─────────────────────────────────────────────────────────────
const item = $input.item.json;
const reviewMeta = $('Keep Only Valid Reviews').item.json;

let analysis = {};
try {
  const raw = item.text || item.response || item.output || '';
  const cleaned = raw.replace(/```json|```/g, '').trim();
  analysis = JSON.parse(cleaned);
} catch (e) {
  // Fallback: infer from star rating if AI parse fails
  const r = reviewMeta.rating || 3;
  analysis = {
    sentiment_label: r >= 4 ? 'positive' : r === 3 ? 'neutral' : 'negative',
    sentiment_score: r >= 4 ? 0.6 : r === 3 ? 0.0 : -0.6,
    emotion_tags: [],
    product_dimension: 'overall',
    key_phrase: reviewMeta.reviewText?.slice(0, 80) || '',
    summary: 'AI parse failed — sentiment inferred from star rating.',
    competitor_mentions: [],
    urgency_level: r <= 2 ? 'high' : 'low',
    response_suggestion: 'Thank you for your feedback. We will look into this.',
    viral_risk: false,
    viral_reason: '',
    brand_loyalty_signal: false,
    awareness_source: 'unknown',
    action_required: r <= 2,
    action_reason: r <= 2 ? 'Low star rating requires CS follow-up' : '',
    cx_score: r * 2
  };
}

// Sanitize types
const sentimentLabel = String(analysis.sentiment_label || 'neutral').toLowerCase();
const sentimentScore = parseFloat(analysis.sentiment_score) || 0;
const actionRequired = analysis.action_required === true || analysis.action_required === 'true';
const viralRisk = analysis.viral_risk === true || analysis.viral_risk === 'true' || reviewMeta.viralRiskPreflag;
const urgencyLevel = String(analysis.urgency_level || 'low').toLowerCase();

// Emoji maps
const sentimentEmoji = { positive: '🟢', neutral: '🟡', negative: '🔴' }[sentimentLabel] || '⚪';
const urgencyEmoji = { critical: '🚨', high: '⚠️', medium: '🔔', low: 'ℹ️' }[urgencyLevel] || 'ℹ️';
const platformEmoji = {
  tokopedia: '🛍️', shopee: '🟠', lazada: '🔵', bukalapak: '🔴', amazon: '📦'
}[String(reviewMeta.platform || '').toLowerCase()] || '🛒';

// Star display
const starDisplay = '⭐'.repeat(Math.round(reviewMeta.rating || 0));

// Competitor mentions as string
const competitorStr = Array.isArray(analysis.competitor_mentions) && analysis.competitor_mentions.length > 0
  ? analysis.competitor_mentions.join(', ')
  : 'None';

// Emotion tags as string
const emotionStr = Array.isArray(analysis.emotion_tags)
  ? analysis.emotion_tags.join(', ')
  : String(analysis.emotion_tags || '');

// Slack urgent message
const slackUrgentMessage =
`${urgencyEmoji} *URGENT BRAND ALERT* — Action Required

${platformEmoji} *Platform:* ${reviewMeta.platform} | ${sentimentEmoji} *Sentiment:* ${sentimentLabel.toUpperCase()} (Score: ${sentimentScore.toFixed(2)})
*Product:* ${reviewMeta.productName} (${reviewMeta.skuCode})
*Star Rating:* ${starDisplay} ${reviewMeta.rating}/5
*Emotion:* ${emotionStr}
*Product Dimension:* ${analysis.product_dimension || 'overall'}

*Review Excerpt:*
_"${reviewMeta.reviewText?.slice(0, 200)}..."_

*Key Phrase:* "${analysis.key_phrase || ''}"
*Urgency:* ${urgencyLevel.toUpperCase()}
${viralRisk ? `🔥 *Viral Risk Detected:* ${analysis.viral_reason || 'High engagement signals'}` : ''}
${competitorStr !== 'None' ? `⚔️ *Competitor Mentioned:* ${competitorStr}` : ''}

*Suggested CS Response:*
_${analysis.response_suggestion || 'Thank you for your feedback.'}_

*Why action is needed:*
${analysis.action_reason || ''}

🔗 <${reviewMeta.productUrl}|View Product on ${reviewMeta.platform}>
_Reviewed: ${reviewMeta.reviewDate} | Processed: ${reviewMeta.runDate}_`;

return [{
  json: {
    // Review metadata
    productName: reviewMeta.productName,
    skuCode: reviewMeta.skuCode,
    platform: reviewMeta.platform,
    category: reviewMeta.category,
    productUrl: reviewMeta.productUrl,
    brandName: reviewMeta.brandName,
    reviewerName: reviewMeta.reviewerName,
    reviewDate: reviewMeta.reviewDate,
    rating: reviewMeta.rating,
    starDisplay,
    photoCount: reviewMeta.photoCount,
    helpfulVotes: reviewMeta.helpfulVotes,
    isVerified: reviewMeta.isVerified,
    sellerReply: reviewMeta.sellerReply,
    wordCount: reviewMeta.wordCount,
    reviewHash: reviewMeta.reviewHash,
    reviewExcerpt: reviewMeta.reviewText?.slice(0, 300) || '',
    runDate: reviewMeta.runDate,
    // AI analysis fields
    sentiment_label: sentimentLabel,
    sentiment_score: sentimentScore,
    sentimentEmoji,
    emotion_tags: emotionStr,
    product_dimension: analysis.product_dimension || 'overall',
    key_phrase: analysis.key_phrase || '',
    summary: analysis.summary || '',
    competitor_mentions: competitorStr,
    urgency_level: urgencyLevel,
    urgencyEmoji,
    response_suggestion: analysis.response_suggestion || '',
    viral_risk: viralRisk,
    viral_reason: analysis.viral_reason || '',
    brand_loyalty_signal: analysis.brand_loyalty_signal === true,
    awareness_source: analysis.awareness_source || 'unknown',
    action_required: actionRequired,
    action_reason: analysis.action_reason || '',
    cx_score: parseFloat(analysis.cx_score) || (reviewMeta.rating * 2),
    // Routing
    slackChannel: reviewMeta.slackChannel,
    slackAlertChannel: reviewMeta.slackAlertChannel,
    notionDatabaseId: reviewMeta.notionDatabaseId,
    // Formatted messages
    slackUrgentMessage,
    platformEmoji
  }
}];

// ─────────────────────────────────────────────────────────────
// BUILD DAILY BRAND HEALTH DIGEST
// Aggregates all processed reviews into a structured report
// ─────────────────────────────────────────────────────────────
const allItems = $input.all();

if (!allItems || allItems.length === 0) {
  return [{
    json: {
      digestMessage: `📊 *BrandPulse 360° — Daily Brand Health Report*\n\nNo reviews were processed today. Check your scraper configuration or product URLs.`,
      total: 0
    }
  }];
}

const reviews = allItems.map(i => i.json);
const runDate = new Date().toISOString().slice(0, 10);

// ── Sentiment breakdown ──
const sentimentCounts = { positive: 0, neutral: 0, negative: 0 };
for (const r of reviews) {
  const s = (r.sentiment_label || 'neutral').toLowerCase();
  if (sentimentCounts[s] !== undefined) sentimentCounts[s]++;
}

// ── Average rating & sentiment score ──
const avgRating = (reviews.reduce((sum, r) => sum + (parseFloat(r.rating) || 0), 0) / reviews.length).toFixed(2);
const avgSentimentScore = (reviews.reduce((sum, r) => sum + (parseFloat(r.sentiment_score) || 0), 0) / reviews.length).toFixed(2);
const avgCxScore = (reviews.reduce((sum, r) => sum + (parseFloat(r.cx_score) || 0), 0) / reviews.length).toFixed(1);

// ── Brand Awareness Score (BAS) calculation ──
const positiveRate = sentimentCounts.positive / reviews.length;
const viralCount = reviews.filter(r => r.viral_risk).length;
const loyaltyCount = reviews.filter(r => r.brand_loyalty_signal).length;
const actionCount = reviews.filter(r => r.action_required).length;
const viralPenalty = Math.min(viralCount * 5, 10); // max -10 pts
const BAS = Math.min(100, Math.max(0, Math.round(
  (parseFloat(avgRating) / 5) * 30 +           // avg rating → max 30pts
  positiveRate * 25 +                           // % positive → max 25pts
  parseFloat(avgSentimentScore) * 10 + 10 +    // sentiment score → max 20pts
  (loyaltyCount / reviews.length) * 10 +       // loyalty signals → max 10pts
  (5) -                                         // base 5pts for competitor benchmark (placeholder)
  viralPenalty                                  // viral risk penalty → max -10pts
)));

const basEmoji = BAS >= 75 ? '🟢' : BAS >= 50 ? '🟡' : '🔴';
const basLabel = BAS >= 75 ? 'Healthy' : BAS >= 50 ? 'Needs Attention' : 'At Risk';

// ── Product dimension breakdown ──
const dimensionCounts = {};
for (const r of reviews) {
  const d = r.product_dimension || 'overall';
  dimensionCounts[d] = (dimensionCounts[d] || 0) + 1;
}
const topDimension = Object.entries(dimensionCounts).sort((a, b) => b[1] - a[1])[0]?.[0] || 'N/A';

// ── Emotion tag frequency ──
const emotionFreq = {};
for (const r of reviews) {
  for (const e of (r.emotion_tags || '').split(',').map(t => t.trim()).filter(Boolean)) {
    emotionFreq[e] = (emotionFreq[e] || 0) + 1;
  }
}
const topEmotions = Object.entries(emotionFreq).sort((a, b) => b[1] - a[1]).slice(0, 3).map(([e, c]) => `${e} (${c})`).join(', ');

// ── Competitor mentions ──
const competitorMap = {};
for (const r of reviews) {
  if (r.competitor_mentions && r.competitor_mentions !== 'None') {
    for (const c of r.competitor_mentions.split(',').map(s => s.trim())) {
      if (c) competitorMap[c] = (competitorMap[c] || 0) + 1;
    }
  }
}
const topCompetitors = Object.entries(competitorMap).sort((a, b) => b[1] - a[1]).slice(0, 3);
const competitorSummary = topCompetitors.length > 0
  ? topCompetitors.map(([brand, count]) => `${brand} (${count}x)`).join(', ')
  : 'None detected';

// ── Platform breakdown ──
const platformCounts = {};
for (const r of reviews) {
  const p = r.platform || 'Unknown';
  platformCounts[p] = (platformCounts[p] || 0) + 1;
}
const platformBreakdown = Object.entries(platformCounts).map(([p, c]) => `${p}: ${c}`).join(' | ');

// ── Top 3 praises ──
const topPraises = reviews
  .filter(r => r.sentiment_label === 'positive')
  .sort((a, b) => b.sentiment_score - a.sentiment_score)
  .slice(0, 3)
  .map(r => `• ${r.key_phrase || r.summary?.slice(0, 80) || ''} [${r.platform}, ${r.rating}⭐]`);

// ── Top 3 complaints ──
const topComplaints = reviews
  .filter(r => r.sentiment_label === 'negative')
  .sort((a, b) => a.sentiment_score - b.sentiment_score)
  .slice(0, 3)
  .map(r => `• ${r.key_phrase || r.summary?.slice(0, 80) || ''} [${r.platform}, ${r.rating}⭐]`);

// ── Viral risk reviews ──
const viralReviews = reviews.filter(r => r.viral_risk).slice(0, 3);

// ── Action items ──
const actionItems = reviews.filter(r => r.action_required).slice(0, 5);

// ── Build Slack digest message ──
let digest = `📊 *BrandPulse 360° — Daily Brand Health Report*\n`;
digest += `📅 ${runDate} | 🛒 Ecommerce Review Intelligence\n`;
digest += `─────────────────────────────────\n\n`;

digest += `${basEmoji} *Brand Awareness Score (BAS): ${BAS}/100 — ${basLabel}*\n`;
digest += `⭐ Avg Rating: ${avgRating}/5 | 📊 Avg Sentiment: ${avgSentimentScore} | 🎯 CX Score: ${avgCxScore}/10\n`;
digest += `📦 Total Reviews Processed: ${reviews.length}\n`;
digest += `🟢 Positive: ${sentimentCounts.positive} | 🟡 Neutral: ${sentimentCounts.neutral} | 🔴 Negative: ${sentimentCounts.negative}\n\n`;

digest += `*📍 Platform Breakdown:* ${platformBreakdown}\n`;
digest += `*🎭 Top Emotions Detected:* ${topEmotions || 'N/A'}\n`;
digest += `*🔧 Most Discussed Dimension:* ${topDimension}\n`;
digest += `*⚔️ Competitor Mentions:* ${competitorSummary}\n\n`;

if (topPraises.length > 0) {
  digest += `*✅ Top Praise Signals:*\n${topPraises.join('\n')}\n\n`;
}

if (topComplaints.length > 0) {
  digest += `*❌ Top Complaint Signals:*\n${topComplaints.join('\n')}\n\n`;
}

if (viralReviews.length > 0) {
  digest += `*🔥 Viral Risk Reviews (${viralCount}):*\n`;
  for (const v of viralReviews) {
    digest += `• ${v.productName} [${v.platform}, ${v.rating}⭐] — ${v.viral_reason || 'High engagement'}\n`;
  }
  digest += '\n';
}

if (actionItems.length > 0) {
  digest += `*⚠️ ${actionItems.length} Review(s) Requiring Action:*\n`;
  for (const a of actionItems) {
    digest += `• ${a.productName} [${a.platform}, ${a.rating}⭐] — ${a.action_reason}\n`;
  }
  digest += '\n';
}

digest += `_BrandPulse 360° | Powered by MrScraper + GPT-4o-mini + n8n_`;

return [{
  json: {
    digestMessage: digest,
    total: reviews.length,
    sentimentCounts,
    avgRating,
    avgSentimentScore,
    avgCxScore,
    BAS,
    basLabel,
    viralCount,
    actionCount,
    competitorSummary,
    runDate,
    slackChannel: reviews[0]?.slackChannel || '#brand-monitoring'
  }
}];

// Extract review URLs from MrScraper map agent response
const inputData = $input.all();
let urls = [];

if (
  inputData.length > 0 &&
  inputData[0].json?.data?.data?.urls &&
  Array.isArray(inputData[0].json.data.data.urls)
) {
  urls = inputData[0].json.data.data.urls;
}

// Filter to only include review-related URLs
const reviewPatterns = [/review/i, /ulasan/i, /rating/i, /comment/i, /feedback/i];
const filteredUrls = urls.filter(url =>
  reviewPatterns.some(p => p.test(url))
);

// Use filtered if available, otherwise use all (some platforms keep reviews on product page)
const finalUrls = filteredUrls.length > 0 ? filteredUrls : urls;

return finalUrls.map((url, index) => ({
  json: {
    url,
    index: index + 1
  }
}));
